import{_ as e,o as r,c as t,a3 as o}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"51. Rates For Saturdays And Sundays","description":"","frontmatter":{"title":"51. Rates For Saturdays And Sundays","eba":"Allied Health Professionals 2021-2026","topics":["hours","overtime","rosters","on-call"]},"headers":[],"relativePath":"ebas/allied-health/hours-of-work/51-rates-for-saturdays-and-sundays.md","filePath":"ebas/allied-health/hours-of-work/51-rates-for-saturdays-and-sundays.md"}'),s={name:"ebas/allied-health/hours-of-work/51-rates-for-saturdays-and-sundays.md"};function l(n,a,d,u,i,c){return r(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="_51-rates-for-saturdays-and-sundays" tabindex="-1">51. Rates For Saturdays And Sundays <a class="header-anchor" href="#_51-rates-for-saturdays-and-sundays" aria-label="Permalink to &quot;51. Rates For Saturdays And Sundays&quot;">​</a></h1><p><strong>51.1</strong> All rostered time of ordinary duty performed on Saturday and Sunday will be paid for at the rate of time and a half.</p><p><strong>51.2</strong> All overtime performed on a Saturday and Sunday will be paid for at the appropriate rate specified in <a href="/eba/ebas/allied-health/hours-of-work/52-overtime.html">clause 52</a>.</p><p><strong>51.3</strong> Any recall to duty on a Saturday or Sunday will be paid in accordance with clause 52 (Overtime), <a href="/eba/ebas/allied-health/hours-of-work/53-recall-return-to-workplace.html">clause 53</a> (Recall – Return to Workplace) and/or <a href="/eba/ebas/allied-health/hours-of-work/54-recall-no-return-to-workplace.html">clause 54</a> (Recall – No Return to Workplace) as applicable.</p><p><strong>51.4</strong> Time off in lieu of overtime may be taken in accordance with subclause 52.9 of this Agreement.</p>',5)])])}const p=e(s,[["render",l]]);export{f as __pageData,p as default};
